previewCss:
.darma-loader-uiverse-soft-3d-cube-flip__loading {
  width: 100px;
  height: 100px;
  background: var(--loader-color, #ffffff);
  border-radius: 12px;
  position: relative;
  transform-style: preserve-3d;
  animation: darma-loader-uiverse-soft-3d-cube-flip-softCubeFlip 2s linear infinite;
}
.darma-loader-uiverse-soft-3d-cube-flip__side { background: var(--loader-color, #ffffff); border-radius: 12px; }
.darma-loader-uiverse-soft-3d-cube-flip__front, .darma-loader-uiverse-soft-3d-cube-flip__back { width: 100px; height: 100px; position: absolute; inset: 0; }
.darma-loader-uiverse-soft-3d-cube-flip__back { transform: translateZ(-10px); }
.darma-loader-uiverse-soft-3d-cube-flip__left, .darma-loader-uiverse-soft-3d-cube-flip__right { width: 10px; height: calc(100% - 12px); top: 6px; position: absolute; background: var(--loader-secondary-color, #efefef); }
.darma-loader-uiverse-soft-3d-cube-flip__left { left: 0; transform-origin: 0; transform: rotateY(90deg); }
.darma-loader-uiverse-soft-3d-cube-flip__right { right: 0; transform-origin: 100%; transform: rotateY(-90deg); }
.darma-loader-uiverse-soft-3d-cube-flip__top, .darma-loader-uiverse-soft-3d-cube-flip__bottom { width: calc(100% - 12px); height: 10px; position: absolute; left: 6px; background: var(--loader-secondary-color, #efefef); }
.darma-loader-uiverse-soft-3d-cube-flip__top { top: -10px; transform-origin: 0 100%; transform: rotateX(90deg); }
.darma-loader-uiverse-soft-3d-cube-flip__bottom { bottom: -10px; transform-origin: 0 0; transform: rotateX(-90deg); }
@keyframes darma-loader-uiverse-soft-3d-cube-flip-softCubeFlip {
  0% { transform: rotate(0); }
  50% { transform: rotateY(180deg); }
  100% { transform: rotateY(180deg) rotateX(-180deg); }
}

